mapper.update:
UPDATE queue_entry
SET status = 'ADMITTED',
    admission_token = #{admissionToken},
    admitted_at = #{admittedAt},
    admission_expires_at = #{admissionExpiresAt},
    updated_at = #{updatedAt}
WHERE event_id = #{eventId}
  AND user_id = #{userId}
  AND status = 'WAITING'

UPDATE queue_entry
SET status = 'ENTERED',
    updated_at = #{updatedAt}
WHERE event_id = #{eventId}
  AND admission_token = #{admissionToken}
  AND status = 'ADMITTED'

UPDATE queue_entry
SET status = 'EXPIRED',
    updated_at = #{updatedAt}
WHERE event_id = #{eventId}
  AND user_id = #{userId}
  AND status = 'ADMITTED'

UPDATE queue_entry
SET status = 'EXPIRED',
    updated_at = #{updatedAt}
WHERE event_id = #{eventId}
  AND user_id = #{userId}
  AND status IN ('WAITING', 'ADMITTED', 'ENTERED')

UPDATE queue_entry
SET status = 'EXPIRED',
    updated_at = #{updatedAt}
WHERE event_id = #{eventId}
  AND user_id LIKE #{userIdPrefix}
  AND status IN ('WAITING', 'ADMITTED', 'ENTERED')
